import json

def evaluate_experts(experts):
    # Extract verdicts and explanations
    verdicts = [expert['verdict'] == 'True' for expert in experts]
    explanations = [expert['explanation'] for expert in experts]

    # Calculate weighted sum of verdicts
    weighted_sum = sum(expert['weight'] * (1 if verdict else 0) for expert, verdict in zip(experts, verdicts))

    # Determine verdict based on weighted sum
    if weighted_sum > 0:
        verdict = 'True'
    elif weighted_sum < 0:
        verdict = 'False'
    else:
        verdict = 'False'  # Inconclusive or poorly justified

    # Determine explanation
    if verdict == 'True':
        explanation = explanations[0]
    else:
        explanation = 'The experts\' reasoning is inconclusive or poorly justified.'

    return {'verdict': verdict, 'explanation': explanation}

